# 2. Стоп-слова (слова, которые не должны попасть в облако)
stop_words = {'и', 'в', 'во', 'на', 'с', 'со', 'по', 'к', 'у', 'о', 'об', 'от', 'под',
              'над', 'за', 'для', 'без', 'до', 'про', 'же', 'ли', 'бы', 'это', 'этот',
              'эта', 'эти', 'тот', 'та', 'те', 'что', 'как', 'так', 'все', 'его', 'ее',
              'их', 'есть', 'был', 'была', 'было', 'были', 'будет', 'будет', 'будем',
              'будете', 'будут', 'весь', 'вся', 'всего', 'всем', 'всеми', 'них', 'себя',
              'свой', 'этих', 'таких', 'таким', 'такие', 'например', 'очень', 'можно'}

# --- Основная логика ---

# Инициализируем анализатор
morph = pymorphy3.MorphAnalyzer()

def lemmatize_text(raw_text, stop_words):
    """
    Очищает текст и приводит все слова к начальной форме (лемме).
    """
    # Приводим к нижнему регистру
    raw_text = raw_text.lower()
    # Убираем всё, кроме букв и пробелов
    raw_text = re.sub(r'[^а-яё\s]', '', raw_text, flags=re.IGNORECASE)

    # Разбиваем на слова
    words = raw_text.split()

    lemmatized_words = []
    for word in words:
        # Пропускаем слишком короткие слова и стоп-слова
        if len(word) <= 2 or word in stop_words:
            continue

        # Получаем нормальную форму (лемму)
        # .normal_form возвращает начальную форму слова
        # Например: 'спорту' -> 'спорт', 'спортивная' -> 'спортивный'
        lemma = morph.parse(word)[0].normal_form

        # Второй проход на случай, если лемма оказалась стоп-словом
        if lemma not in stop_words:
            lemmatized_words.append(lemma)

    return ' '.join(lemmatized_words)

# Обрабатываем текст
processed_text = lemmatize_text(text, stop_words)

# --- Создание и отображение облака слов ---
wordcloud = WordCloud(
    width=800,
    height=400,
    background_color='white',
    colormap='viridis',
    max_words=100,
    relative_scaling=0.5,
    random_state=42
).generate(processed_text)

# Визуализируем
plt.figure(figsize=(10, 5))
plt.imshow(wordcloud, interpolation='bilinear')
plt.axis('off')
plt.title('Облако слов с лемматизацией', fontsize=16)
plt.show()

# Сохраняем результат
wordcloud.to_file('wordcloud_lemmatized.png')
print("Облако слов успешно сохранено как 'wordcloud_lemmatized.png'")